    is_deleted, crte_time, updt_time
) VALUES (
    #{poolId}, #{relationType}, #{relationPoolId}, #{relationPoolName}, #{sortOrder}, #{remark},
    #{isDeleted}, #{crteTime}, #{updtTime}
)

INSERT INTO ip_pool_relation_evt (
    id, pool_id, relation_type, relation_pool_id, relation_pool_name, sort_order, remark,
    is_deleted, crte_time, updt_time, opter_id, opt_time, oprt_type
)
