mapper.select:
SELECT u.id, u.user_name AS userName, u.is_deleted AS isDeleted, u.crte_time AS crteTime, u.updt_time AS updtTime, GROUP_CONCAT(DISTINCT r.role_name ORDER BY r.sort_order ASC SEPARATOR '、') AS roleName FROM ip_user u LEFT JOIN ip_user_role ur ON ur.user_id = u.id AND ur.is_deleted = 0 LEFT JOIN ip_role r ON r.id = ur.role_id AND r.is_deleted = 0 WHERE u.is_deleted = 0
AND EXISTS ( SELECT 1 FROM ip_user_role ur2 WHERE ur2.user_id = u.id AND ur2.is_deleted = 0 AND ur2.role_id IN
#{roleId}
)
AND u.user_name LIKE CONCAT('%', #{keyword}, '%')
GROUP BY u.id, u.user_name, u.is_deleted, u.crte_time, u.updt_time ORDER BY u.id ASC

